  ('immigration-1aab856d-moex-00464', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲放學回家，路過A宅門口，A所飼養的猛犬因發情突然撞開圍欄衝出欲攻擊甲，甲逃跑，但猛 犬仍緊追在後，甲為求自衛遂搶下路人B的球棒，對準猛犬的頭猛擊，當場將A所飼養的猛犬擊 斃。下列敘述何者正確？', '["甲對A與B均可主張正當防衛", "甲對A可主張正當防衛，對B則可主張緊急避難", "甲對A可主張緊急避難，對B則可主張正當防衛", "甲對A、B均可主張緊急避難"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 14, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00465', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲因前後犯三件詐欺案遭法院判決有罪，應數罪併罰，法院針對前後三件詐欺罪分別宣告1年2 個月、1年6個月與2年有期徒刑。依據刑法第51條之規定，法院定數罪併罰之執行刑時，不得 諭知下列何種刑度？', '["1年6個月有期徒刑", "2年有期徒刑", "2年8個月有期徒刑", "3年6個月有期徒刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00466', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '刑法關於沒收的規定，下列敘述何者錯誤？', '["違禁物得單獨宣告沒收", "犯罪工具雖屬於犯罪行為人以外之法人所有，若係無正當理由而取得，亦得沒收之", "犯罪所得沒收僅得針對自然人或法人，對非法人團體無法沒收犯罪所得", "若認定犯罪所得及追徵之範圍與價額顯有困難時，得以估算認定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00467', 'immigration-1aab856d', 'immigration-1aab856d-moex-110-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲、乙兩人共謀在捷運站扒竊，甲為防萬一暗中攜帶一把小尖刀在身上，但乙對於甲攜帶尖刀之 事並不知情。之後，甲、乙兩人在捷運站內選定目標A，依計畫由乙假意跟A問路，甲隨即趁A 與乙交談分心之際將A口袋內之皮夾扒走，之後甲、乙將皮夾內的現金6000元平分。試問甲、 乙之行為應成立何罪？', '["甲、乙兩人成立加重竊盜罪的共同正犯", "甲成立加重竊盜罪、乙對甲攜帶尖刀不知情僅成立普通竊盜罪", "甲、乙兩人成立加重搶奪罪的共同正犯", "甲成立加重搶奪罪、乙對甲攜帶尖刀不知情僅成立普通搶奪罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:56+00:00", "source_pdf_sha1": "3218f7df9c31", "answer_pdf_sha1": "f14161b9d7ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "702", "s": "0510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
